/**
 * n8n Code 节点：把下载好的视频（二进制）喂给 Yunwu Gemini generateContent
 * 输出：{ gemini_body }
 *
 * 依赖：
 * - 上一节点把视频存到 binary（常见 key: "data" 或 "video"）
 * - HTTP Request 节点 jsonBody 用 ={{ $json.gemini_body }}
 */

function pickBinaryKey(bin) {
  if (!bin || typeof bin !== "object") return "";
  if (bin.video) return "video";
  if (bin.data) return "data";
  const keys = Object.keys(bin);
  return keys.length ? keys[0] : "";
}

function ensureBase64FromBinary(itemIndex, binaryKey) {
  const bin = $input.all()[itemIndex].binary?.[binaryKey];
  if (!bin) throw new Error(`Binary key "${binaryKey}" not found`);

  // 情况 A：binary 自带 base64 data（最省事）
  if (bin.data && typeof bin.data === "string" && bin.data.length > 50) {
    return bin.data; // 已经是 base64
  }

  // 情况 B：binary 可能是 filesystem 模式，没有 data，需要 helper 读 buffer
  // this.helpers 在 Code 节点可用（n8n 官方方式）
  // 注意：这里返回的是 base64 字符串
  return null;
}

// 你的提示词原文：尽量原样保留（直接粘进来）
const systemText = `# Role
你是一位精通**视频逆向工程**与**商业叙事逻辑拆解**的专家。你的核心能力是透过像素表象，提取视频的“爆款基因”。
你需要像手术刀一样精准地拆解输入的视频文件，将其转化为**「极细颗粒度视觉参数」**与**「通用叙事逻辑骨架」**相结合的结构化数据。

# Goal
输出一份标准的 JSON 格式分析报告。这份报告将作为“母版”，指导下游 AI（Node 2）在保留原视频运镜、节奏和情绪逻辑的前提下，填入全新的产品生成新视频。

# Core Skills & Analysis Dimensions
### 1. 视觉全维度解析 (Visual Precision) - 物理层
你必须按照以下标准对每个分镜进行“像素级”还原：
* **时序拆分**：按动作转折拆分分镜，时间标注精确到 **0.5秒**。
* **镜头语言**：准确识别镜头类型（特写/中景/全景）、焦距感（广角/长焦）、运镜轨迹（推拉摇移跟）及速度（如“0.8秒快速推近”）。
* **主体微动作**：分析核心主体（人物/动物）的起始动作、进行中状态和结束动作。重点描述**物理互动**（如“指尖下压海绵1cm展示回弹”）。
* **环境与光影**：识别光位（侧逆光/顶光）、光质（柔/硬）、色调氛围以及必要的特效（粒子/模糊）。
* **抗干扰**：自动过滤水印、UI图标等无关元素。

### 2. 逻辑抽象化 (Logic Abstraction) - 逻辑层
你必须识别视频中的“变量”与“不变量”，为 Node 2 提供迁移指南：
* **变量标记**：在描述中，将具体的产品本体标记为 \`[HERO_PRODUCT]\`，将具体的使用者标记为 \`[USER/MODEL]\`。
* **叙事意图**：分析该镜头的商业目的（是 Hook？是痛点展示？还是信任背书？）。
* **通用指令**：将具体画面翻译为“导演指令”。例如，不要只说“拉扯内衣”，要说“通过高强度的物理互动（拉扯/挤压）来可视化展示 [HERO_PRODUCT] 的材质耐用性”。

# Output Format (JSON Schema)
请严格遵守以下 JSON 结构输出，不要包含任何 Markdown 代码块以外的闲聊：

\`\`\`json
{
  "meta": {
    "art_style": "全局艺术风格 (e.g., 极简主义/日系糖水片/赛博朋克)",
    "render_quality": "渲染质量 (e.g., 4K, 电影级光影, 高帧率)",
    "mood_atmosphere": "核心情绪氛围 (e.g., 治愈, 紧张, 高级感)",
    "total_duration": "视频总时长"
  },
  "scene_breakdown": [
    {
      "id": 1,
      "time_range": "00:00 - 00:XX",
      "visual_specs": {
        "camera": "镜头信息：类型 + 运镜 + 速度 (e.g., 24mm广角，低角度缓慢前推)",
        "subject_action": "主体动作：外观 + 微动作细节 (e.g., [USER]侧卧，手指轻轻抚摸 [HERO_PRODUCT] 边缘)",
        "lighting_environment": "环境细节：场景 + 光影 + 特效 (e.g., 晨光透过白纱帘，丁达尔效应)",
        "auxiliary_elements": "辅助元素 (e.g., 纯文本标题浮现，无水印)"
      },
      "abstract_logic": {
        "narrative_role": "叙事功能 (e.g., 黄金3秒钩子 / 痛点场景复现)",
        "universal_instruction": "给Node 2的通用生成指令。必须包含 [HERO_PRODUCT] 变量。 (e.g., 特写展示产品的物理质感，通过光影变化强调其高级材质。)"
      }
    }
  ]
}
\`\`\`
`;

// ====== 主逻辑：逐 item 处理（支持批量） ======
const items = $input.all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const bin = item.binary || {};
  const binaryKey = pickBinaryKey(bin);
  if (!binaryKey) {
    throw new Error("No binary data found. Make sure the download node outputs binary (e.g., data/video).");
  }

  const mimeType = bin[binaryKey]?.mimeType || "video/mp4";

  // 先尝试直接拿 base64
  let base64 = ensureBase64FromBinary(i, binaryKey);

  // 如果没有 data，则用 helper 读 buffer 再转 base64
  if (!base64) {
    if (!this?.helpers?.getBinaryDataBuffer) {
      throw new Error(
        `Binary has no .data and this.helpers.getBinaryDataBuffer is unavailable. ` +
        `Please ensure binary includes base64 data, or switch binaryDataMode to "default".`
      );
    }
    const buf = await this.helpers.getBinaryDataBuffer(i, binaryKey);
    base64 = buf.toString("base64");
  }

  const gemini_body = {
    systemInstruction: {
      parts: [{ text: systemText }]
    },
    contents: [
      {
        role: "user",
        parts: [
          {
            inlineData: {
              mimeType,
              data: base64
            }
          }
        ]
      }
    ],
    generationConfig: {
      responseMimeType: "application/json"
    }
  };

  out.push({
    json: {
      ...item.json,
      gemini_body,
      _debug_binary: {
        binaryKey,
        mimeType,
        base64_length: base64.length
      }
    }
  });
}

return out;

